&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot; data-contrast=&quot;auto&quot;&gt;Lake St. Louis, MO&lt;/span&gt;&lt;/li&gt;
